def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        decay = 0.75
        for depth in range(1, 7):
            if residual <= 0:
                score += (20 / (depth ** 1.5))
            else:
                if depth % 2 == 0:
                    score += ((1 / residual) ** 0.5) * (depth ** 1.2)
                else:
                    score += (np.log1p(residual) / residual) * depth
            residual *= decay
            decay *= 0.9
        if capacity > 4 * item:
            score *= 0.8
        elif capacity > 3 * item:
            score *= 0.9
        elif capacity > 2 * item:
            score *= 1.05
        elif capacity > item:
            score *= 1.2
        else:
            score *= 1.5
        penalty = 0
        for check in range(1, int(np.ceil(item)) + 1):
            if (capacity + check) % 3 == 0:
                penalty += 0.3 * check * ((check % 2) + 1)
            elif (capacity + check) % 5 == 0:
                penalty -= 0.5 * check * (1 if check % 3 == 0 else 0.5)
            else:
                penalty += (-1) ** check * 0.1 * check
        score += penalty
        adjustment = 0
        for j in range(2, 10):
            if j == 7:
                continue
            if capacity % j == 0:
                adjustment += (j * 0.3) if j % 2 == 0 else -(j * 0.2)
            else:
                adjustment += (j * 0.1)
        score += adjustment
        if score < 0:
            priorities[i] = 0
        elif score > 200:
            priorities[i] = 200
        else:
            priorities[i] = score
    return priorities
